def ranges_overlap(start1, end1, start2, end2):
    """Check if two datetime ranges [start1, end1) and [start2, end2) overlap.
    Handles both naive and timezone-aware datetimes.
    Returns True if there is any overlap.
    """
    # Convert timezone-aware datetimes to UTC, keep naive datetimes as-is
    def to_comparable(dt):
        if dt.tzinfo is not None:
            return dt.utctimetuple()
        return dt.timetuple()

    # Check if we have mixed naive/aware datetimes
    datetimes = [start1, end1, start2, end2]
    aware_count = sum(1 for dt in datetimes if dt.tzinfo is not None)

    if 0 < aware_count < 4:
        # Mixed case: convert all to UTC for comparison
        # Treat naive datetimes as UTC
        def to_utc_comparable(dt):
            if dt.tzinfo is not None:
                return dt.utctimetuple()
            else:
                return dt.timetuple()  # Assume naive is UTC

        s1 = to_utc_comparable(start1)
        e1 = to_utc_comparable(end1)
        s2 = to_utc_comparable(start2)
        e2 = to_utc_comparable(end2)
    else:
        # All same type (all naive or all aware)
        s1 = to_comparable(start1)
        e1 = to_comparable(end1)
        s2 = to_comparable(start2)
        e2 = to_comparable(end2)

    # Check for zero-length ranges first
    if s1 >= e1 or s2 >= e2:
        return False

    # Check overlap: ranges [s1, e1) and [s2, e2) overlap if s1 < e2 and s2 < e1
    return s1 < e2 and s2 < e1

