import copy
import json

def apply_patch(document, patches):
    """Apply a list of JSON Patch operations (RFC 6902 subset) to a document.
    Supports: add, remove, replace operations.
    Path format: '/key/index/nested' (JSON Pointer, RFC 6901)
    Returns the modified document.
    """
    result = copy.deepcopy(document)

    def unescape_json_pointer(token):
        """Unescape JSON Pointer token according to RFC 6901"""
        return token.replace('~1', '/').replace('~0', '~')

    def parse_path(path):
        """Parse JSON Pointer path into tokens"""
        if path == '':
            return []
        if not path.startswith('/'):
            raise ValueError(f"Invalid JSON Pointer: {path}")

        # Split and unescape each part
        parts = path[1:].split('/')
        return [unescape_json_pointer(part) for part in parts]

    for patch in patches:
        op = patch['op']
        path = patch['path']
        value = patch.get('value')

        # Parse JSON pointer
        parts = parse_path(path)

        # Handle root document operations
        if not parts:
            if op == 'add' or op == 'replace':
                result = value
            elif op == 'remove':
                result = None
            continue

        # Navigate to parent
        parent = result
        for part in parts[:-1]:
            if isinstance(parent, list):
                parent = parent[int(part)]
            else:
                parent = parent[part]

        target = parts[-1]

        if op == 'add':
            if isinstance(parent, list):
                if target == '-':
                    parent.append(value)
                else:
                    parent.insert(int(target), value)
            else:
                parent[target] = value

        elif op == 'remove':
            if isinstance(parent, list):
                del parent[int(target)]
            else:
                del parent[target]

        elif op == 'replace':
            if isinstance(parent, list):
                parent[int(target)] = value
            else:
                parent[target] = value

    return result

